  if (!allowed) {
    webhookBaseUrl = 'https://amanguleria.app.n8n.cloud/webhook';
    console.warn('[SECURITY] webhookBaseUrl rejected, falling back to default');
  }
} catch(e) { webhookBaseUrl = 'https://amanguleria.app.n8n.cloud/webhook'; }

// ── Mode: 'light' (A1+A2+A3+A5) or 'full' (all 8 agents) ──
