const a1 = o(a1_raw); const a2 = a2_raw?.outputs || a2_raw || {}; const a3 = o(a3_raw); const a4 = o(a4_raw); const a5 = o(a5_raw);
const a6 = a6_raw.outputs || a6_raw || {}; const a7 = a7_raw.outputs?.outputs || a7_raw.outputs || a7_raw || {}; const a8 = o(a8_raw);
const a5MonthlyBase = parseFloat((a5.revenue_range?.monthly_base || '0').replace(/[^0-9.]/g, '')) || 0;
const monthlyRent = parseFloat(inputs.monthly_rent_budget_max || '0') || 0;
let a5RentBurdenPct = null, a5RentBurdenLabel = 'Unknown', a5RentBurdenScore = 50;
if (a5MonthlyBase > 0 && monthlyRent > 0) {
  a5RentBurdenPct = parseFloat(((monthlyRent / a5MonthlyBase) * 100).toFixed(1));
  a5RentBurdenLabel = a5RentBurdenPct <= 8 ? 'Excellent' : a5RentBurdenPct <= 12 ? 'Healthy' : a5RentBurdenPct <= 15 ? 'Caution' : a5RentBurdenPct <= 20 ? 'High Risk' : 'Avoid';
