}
const top5Competitors = (a1.competitor_profiles || []).filter(c => typeof c.rating === 'number' && !isNaN(c.rating)).sort((a, b) => { if (b.within_500m !== a.within_500m) return b.within_500m ? 1 : -1; if ((b.rating||0) !== (a.rating||0)) return (b.rating||0)-(a.rating||0); return (b.review_count||0)-(a.review_count||0); }).slice(0, 8);

// Enrich top competitors with maps_url from raw_maps_data
const rawMaps = (a1_raw.raw_maps_data || []);
const enrichedCompetitors = top5Competitors.map(c => {
